def shade(cell, fill):
    tcPr=cell._tc.get_or_add_tcPr(); shd=OxmlElement('w:shd'); shd.set(qn('w:fill'),fill); tcPr.append(shd)
def set_cell_text(cell, text, bold=False, size=9):
    cell.text=''; p=cell.paragraphs[0]; p.paragraph_format.space_after=Pt(0); r=p.add_run(str(text)); r.bold=bold; r.font.size=Pt(size); cell.vertical_alignment=WD_CELL_VERTICAL_ALIGNMENT.CENTER
def table(headers, rows, widths=None):
    t=doc.add_table(rows=1, cols=len(headers)); t.style='Table Grid'; t.alignment=WD_TABLE_ALIGNMENT.CENTER
    for i,h in enumerate(headers): set_cell_text(t.rows[0].cells[i],h,True); shade(t.rows[0].cells[i],'E8EEF5')
    for row in rows:
        cells=t.add_row().cells
        for i,val in enumerate(row): set_cell_text(cells[i],val)
    if widths:
        for row in t.rows:
            for i,w in enumerate(widths): row.cells[i].width=Inches(w)
    doc.add_paragraph('')
    return t
def p(text='', style=None, boldlead=None):
    para=doc.add_paragraph(style=style)
    if boldlead and text.startswith(boldlead):
        para.add_run(boldlead).bold=True; para.add_run(text[len(boldlead):])
    else: para.add_run(text)
    return para
def bullet(text): return doc.add_paragraph(text,style='List Bullet')
def heading(text, level=1): return doc.add_heading(text,level=level)
def code(text):
    para=doc.add_paragraph(); para.paragraph_format.left_indent=Inches(.25); para.paragraph_format.right_indent=Inches(.25); para.paragraph_format.space_after=Pt(8)
    for line in text.strip().splitlines():
        r=para.add_run(line+'\n'); r.font.name='Consolas'; r._element.rPr.rFonts.set(qn('w:eastAsia'),'Consolas'); r.font.size=Pt(8); r.font.color.rgb=RGBColor(40,40,40)
    shd=OxmlElement('w:shd'); shd.set(qn('w:fill'),'F3F5F7'); para._p.get_or_add_pPr().append(shd)
def figure(title, explanation):
    t=doc.add_table(rows=1,cols=1); t.alignment=WD_TABLE_ALIGNMENT.CENTER; c=t.cell(0,0); shade(c,'F4F6F9'); c.width=Inches(6.2); c.text=''
    pr=c.paragraphs[0]; pr.alignment=WD_ALIGN_PARAGRAPH.CENTER; pr.paragraph_format.space_before=Pt(24); pr.paragraph_format.space_after=Pt(24); r=pr.add_run('[ SCREENSHOT PLACEHOLDER ]\n'+title); r.bold=True; r.font.color.rgb=RGBColor.from_string('1F4D78'); r.font.size=Pt(12)
    cap=doc.add_paragraph('Figure '+str(figure.n)+'. '+title+'. '+explanation,style='Caption'); figure.n+=1
figure.n=1
