heading('5. Database Design / Structure',1)
heading('5.1 Current versus Proposed Design',2); p('Current implementation: no database exists. The catalogue is a static JavaScript array; reviews, ratings and prices are display fields in that array. Browser storage is used only for the visitor counter and session marker. The following is a proposed normalized production design, clearly separate from the delivered implementation.')
mermaid('5.2 Proposed production ER Diagram','''erDiagram\n CATEGORY ||--o{ PRODUCT : classifies\n PRODUCT ||--o{ REVIEW : receives\n USER ||--o{ REVIEW : writes\n USER ||--o{ WISHLIST : owns\n PRODUCT ||--o{ WISHLIST : saved\n USER ||--o{ ORDER : places\n ORDER ||--|{ ORDER_ITEM : contains\n PRODUCT ||--o{ ORDER_ITEM : ordered\n USER ||--o{ CONTACT_MESSAGE : sends\n CATEGORY { int category_id PK\n string name UK\n }\n PRODUCT { int product_id PK\n int category_id FK\n string name\n decimal price\n decimal old_price\n decimal rating\n int review_count\n }\n USER { int user_id PK\n string email UK\n string full_name\n }\n REVIEW { int review_id PK\n int product_id FK\n int user_id FK\n tinyint rating\n text comment\n }\n WISHLIST { int wishlist_id PK\n int user_id FK\n int product_id FK\n }\n ORDER { int order_id PK\n int user_id FK\n decimal subtotal\n string status\n }\n ORDER_ITEM { int order_item_id PK\n int order_id FK\n int product_id FK\n int quantity\n decimal unit_price\n }\n CONTACT_MESSAGE { int message_id PK\n int user_id FK\n string name\n string email\n text message\n }''')
heading('5.3 Proposed Table Structures and Constraints',2)
table(['Table','Key fields and types','Constraints/relationships'],[['categories','category_id INT PK; name VARCHAR(80)','name UNIQUE, NOT NULL.'],['products','product_id INT PK; category_id INT FK; name VARCHAR(180); type VARCHAR(120); colour VARCHAR(60); brand VARCHAR(80); price DECIMAL(12,2); old_price DECIMAL(12,2) NULL; rating DECIMAL(2,1); description TEXT','price >= 0; old_price > price when supplied; belongs to one category.'],['users','user_id INT PK; full_name VARCHAR(120); email VARCHAR(254)','email UNIQUE; required for account-based features.'],['reviews','review_id INT PK; product_id INT FK; user_id INT FK; rating TINYINT; comment TEXT','rating between 1 and 5; one product and one author.'],['contact_messages','message_id INT PK; user_id INT FK NULL; name VARCHAR(120); email VARCHAR(254); message TEXT; created_at TIMESTAMP','name/email/message required; optional linked user.'],['wishlists','wishlist_id INT PK; user_id INT FK; product_id INT FK; created_at TIMESTAMP','UNIQUE(user_id, product_id).'],['orders','order_id INT PK; user_id INT FK; subtotal DECIMAL(12,2); status VARCHAR(30); created_at TIMESTAMP','subtotal >= 0; belongs to one user.'],['order_items','order_item_id INT PK; order_id INT FK; product_id INT FK; quantity INT; unit_price DECIMAL(12,2)','quantity > 0; preserves price at time of order.']], [1.1,3.05,2.85])
heading('5.4 Normalization',2); p('The proposed schema is in third normal form: categories are separated from products; user identity is separated from reviews, wishlist rows and orders; and order lines hold the repeatable product/quantity relationship. Prices in order_items intentionally preserve transactional history rather than relying on a future products.price value.')

